var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"제길…… 왜 이리 가슴이 답답한지 모르겠군. 강 팀장에게 심장약이라도 받아 와야 하는 건가.","JPN":"くそ……なんでこんなに息苦しいんだ？　心臓の薬でも貰って来た方がいいのか？","ENG":"Dammit... Why does my chest feel so tight? I should probably get some heart medicine from Miss Kang.","TWN":"該死……心怎麼揪得這麼緊，是不是要跟姜隊長要個心臟藥來吃吃？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"……음?","JPN":"……む？","ENG":"Hmm?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"둘이 거기서 뭘 구경하는 거냐.","JPN":"そこ、二人で何を見てるんだ。","ENG":"What are you two looking at?","TWN":"你們二個在這裡看什麼？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"3분 내로 담당 구역까지 가야 돼. 어서 장비 챙겨라.","JPN":"3分以内に担当区域まで行くんだ。早く装備を持て。","ENG":"You need to get to your positions within 3 minutes. So go get your gear.","TWN":"3分鐘後要前往負責區域，趕快把裝備準備好！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"티, 팀장님……! 잠시 저기 좀 봐 주시겠습니까?","JPN":"ち、チーム長……！　あそこを見てください！","ENG":"S-sir...! Please look over there now?","TWN":"隊…隊長……！你看一下那裡！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"큰일났어요. 지금 대균열에……","JPN":"大変なんです。今大亀裂に……","ENG":"This is bad. The Grand Dimension Crevice...","TWN":"大事不好了，大峽谷現在……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뭐야. 저 괴물은.","JPN":"何だ。あの化け物は。","ENG":"What the hell is that monster?","TWN":"搞什麼，那什麼怪物！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관측조, 보고하라! 지금 영상에 찍히고 있는 건 대체 뭔가!</color>","JPN":"<color=#ffd34c>観測組、報告しろ！　今映像に映っているのはいったい何だ！</color>","ENG":"<color=#ffd34c>Observation team, report! What's that thing being filmed?!</color>","TWN":"<color=#ffd34c>觀測組，立刻回報！現在畫面拍到的到底是什麼東西！</color>"},"stage":{"bg":"MS_1007","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모, 모르겠습니다……!</color>","JPN":"<color=#ffd34c>わ、わかりません……！</color>","ENG":"<color=#ffd34c>W-we don't know, sir...!</color>","TWN":"<color=#ffd34c>不…不知道……！</color>"},"stage":{"bg":"MS_1007","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>숨…… 숨이……! 쉬어지지 않아서……! 헉……! 허억……!</color>","JPN":"<color=#ffd34c>息……息が……！　できなくて……！　はあ……！　はあっ……！</color>","ENG":"<color=#ffd34c>I... I can't... breathe...! *Gasp...!* *Gasp...!*</color>","TWN":"<color=#ffd34c>我……我……！沒辦法喘氣……！呼……！呼……！</color>"},"stage":{"bg":"MS_1007","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이봐! 정신 차려! 이봐!!</color>","JPN":"<color=#ffd34c>おい！　しっかりしろ！　おい！！</color>","ENG":"<color=#ffd34c>Hey! Get a hold of yourself! Hey!!</color>","TWN":"<color=#ffd34c>喂！你醒醒！喂！！</color>"},"stage":{"bg":"MS_1007","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이런 빌어먹을……!</color>","JPN":"<color=#ffd34c>ちくしょう……！</color>","ENG":"<color=#ffd34c>Damn it...!</color>","TWN":"<color=#ffd34c>該死的……！</color>"},"stage":{"bg":"MS_1007","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>소집된 태스크포스 전부 퇴각시키고 회의장에 연락해! 어서!</color>","JPN":"<color=#ffd34c>招集した全タスクフォースを退却させて会議場に連絡しろ！　早く！</color>","ENG":"<color=#ffd34c>Contact all TASKFORCE and tell them to retreat! And contact the conference room, now!</color>","TWN":"<color=#ffd34c>立刻讓召集的特遣勢力全部撤退，快通報！快！</color>"},"stage":{"bg":"MS_1007","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"실물은 더욱 장엄하군. 껍데기의 존재감만으로도 공포를 불러일으키는 건가.","JPN":"本物はなお荘厳だな。殻の存在感だけでも恐怖心を呼び起こしているのか。","ENG":"She's even more majestic in person. Her mere presence evokes fear, even when it’s empty.","TWN":"實體更雄偉呢，外表就足以令人感到恐懼嗎？"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"대균열 사이로 보이는 저게…… 네가 말한 마왕이니?","JPN":"大亀裂の間から見えるあれ……あなたの言っていた魔王なの？","ENG":"That thing we see beyond the Grand Dimension Crevice... Is that the Demon Lord you were talking about?","TWN":"從大峽谷中看到的那個……就是你所說的魔王嗎？"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"엄밀히 구분하면 저건 마왕에게 패배한 마왕이라네.","JPN":"厳密に言うとあれは魔王に敗北した魔王だ。","ENG":"Strictly speaking, \\"that\\" is a Demon Lord defeated by another Demon Lord.","TWN":"要嚴格區分的話，那是輸給魔王的魔王。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그 둘 사이엔 아주 큰 차이가 존재하지.","JPN":"両者にはとても大きな違いがあるのだよ。","ENG":"The two of them are completely different.","TWN":"二者的差距非常大。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"신이 묵인하는 가운데, 왕좌를 빼앗기고…….","JPN":"神の黙認の下、王座を奪われ……","ENG":"While God turns a blind eye, the throne's been taken away...","TWN":"在神的默許下寶座被奪走……"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"북의 폭군에게 의식마저 둘로 갈라져 버렸으니 말이야.","JPN":"北の暴君に意識まで二つに裂かれてしまったのだからな。","ENG":"And her consciousness, torn in two by the Tyrant of the North.","TWN":"結果被北方的暴君將意識一分為二。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"레비아탄이란 마왕은 문자 그대로 짐승이었어.","JPN":"レヴィアタンという魔王は文字どおり獣だった。","ENG":"The Demon Lord Leviathan was, literally, a beast.","TWN":"利維坦魔王，顧名思義就是怪獸。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"각자가 이성과 본능뿐인, 하나이자 둘인 마왕이었지.","JPN":"理性と本能に分かれた、一つであり二つの魔王だったのだよ。","ENG":"It was a Demon Lord with reason and instinct, the two halves that made one.","TWN":"各自有理性和本能，是一體，也是二個個體的魔王。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하지만 보게나. 그렇기 때문에 지금 저것은 이성도 본능도 잃은 고깃덩어리에 불과해.","JPN":"だが見てごらん。だからこそ今のあれは理性も、本能も失った肉の塊に過ぎない。","ENG":"But look at her now. Without reason or instinct, she is nothing but a piece of meat.","TWN":"不過你看，她現在不過是個失去理性和本能的大塊頭。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"저 육신 안에 아무리 강대한 힘이 깃들어 있어도, 의지가 깃들지 않는 한 주인 잃은 무기나 마찬가지지.","JPN":"あの肉体の中にいくら強大な力が宿っているとしても、意志が宿っていない以上は主をなくした武器も同然だ。","ENG":"No matter what power lies within her body, it is a weapon without a master if no one is controlling it.","TWN":"就算在那副軀殼裡放入在強大的力量，由於沒有意志，就與失去主人的武器無異。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……저런 보기만 해도 숨막히는 괴물을 불러들여 어쩔 셈이니?","JPN":"……見ているだけでも息が詰まるような化け物を呼び寄せてどうするつもりなの？","ENG":"...What are you scheming, calling a monster like that here?","TWN":"……你把那個光看就令人感到窒息的怪物召喚出來，是打算做什麼？"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"신중하게 대답하렴. 맨션은 세상을 더 아름답게 가꾸기 위해 존재한단다.","JPN":"慎重に答えなさい。マンションは世の中をもっと美しくするために存在しているの。","ENG":"I suggest you choose your next words carefully. Mansion exists to make the world a more beautiful place.","TWN":"請謹慎回答，曼森是為了裝飾更美好的世界而存在的。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아무렴 내가 세상을 없애려고 저 괴물을 끌어들였겠나.","JPN":"私が世界を滅ぼすためにあの化け物を引き込むわけがないだろう？","ENG":"Do you really think I brought this monster here to destroy the world?","TWN":"我會為了毀滅世界而召喚那種怪物嗎？"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼? 너 말고 저런 걸 불러들일 녀석이 누가 있냔 말이야.","JPN":"そうじゃなかったら何？　あなた以外にあんなものを呼び寄せるようなやつはいないわ。","ENG":"Then? Who else is reckless enough to do such a thing?","TWN":"不然呢？不是你，還有哪個傢伙會召喚那種東西？"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"한 자리에 모인 본래의 의지에 이끌려 자연스럽게 온 것이지.","JPN":"一つの場所に集まった本来の意志に導かれて自然とやって来たのさ。","ENG":"It came here naturally, attracted by her two halves gathering in one place.","TWN":"原本的意志聚集在一起後，自然會把它引來。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"레비아탄과 손 잡은 것은 사실이라네. 숙주를 삼킨 뒤 방황하던 그녀에게 먼저 제안했어.","JPN":"レヴィアタンと手を組んだのは事実だ。宿主を飲み込んだ後に彷徨っていた彼女に先に提案してね。","ENG":"It is true that I joined hands with Leviathan. I offered this proposal when she was wandering aimlessly after consuming her host.","TWN":"和利維坦合作是事實，是我先向吞噬掉宿主後徬徨的她提議。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하지만 나는 어디까지나 동생과 만날 기회를 마련해 준다고 했을 뿐이야.","JPN":"だが私は妹と会う機会を作ってあげると話しただけだよ。","ENG":"But all I proposed was that I help her find her younger sister.","TWN":"不過我只說我會提供見到妹妹的機會而已。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그러니? 유언이라기에는 꽤나 짤막하구나.","JPN":"そう？　遺言にしてはたいぶ短いわね。","ENG":"Is that so? That's quite short for your last words.","TWN":"然後呢？你的遺言似乎有點短。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"나를 파괴하고 싶다면 기꺼이 그럴 기회를 주지, 마담.","JPN":"私を破壊したいというのなら喜んで機会を与えてあげよう、マダム。","ENG":"Madam, if you want to destroy me, I will happily give you the opportunity.","TWN":"你想毀掉我的話，我很樂意提供夫人機會。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"다만… 결정은 모든 일이 마무리된 뒤에 내려도 늦진 않을 거야.","JPN":"ただ……すべてのことが終わった後に決めても遅くないはずだ。","ENG":"But… I believe it won't be too late even after all my work has been complete.","TWN":"只是…等一切結束後再決定也不遲。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷, 정말 부르지도 않았는데 오는 거 있지?","JPN":"えへっ、本当に呼んでもいないのに来ちゃったね。","ENG":"Hehe, it really came even though I didn't call for it.","TWN":"嘿嘿，我又沒叫她來，她還真的來咧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"바야흐로 레비아탄 대부활! 잔뜩 사냥해서 아스모데우스에게도 갚아 주자!","JPN":"まさにレヴィアタンの大復活！　いっぱい狩ってアスモデウスにも仕返ししてやろう！","ENG":"This is the great revival of Leviathan! Let's hunt and get stronger, and return Asmodeus' favor!","TWN":"正好利維坦大復活！我要盡情狩獵後向阿斯蒙蒂斯報仇！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"하아…… 하아……","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"관리부장, 무서워하지 마. 무서워하면 숨을 쉴 수 없어.","JPN":"管理部長、怖がらないで。怖がると息ができない。","ENG":"Hana, don't be scared. It'll be harder to breathe if you are.","TWN":"管理部長，你別怕，怕的話會無法呼吸。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그게 말처럼 쉽지가 않다구.","JPN":"それがそう簡単じゃないのよね。","ENG":"Well, that's easier said than done.","TWN":"說得倒容易。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"거북이가 상어를 보고 놀라는 것처럼, 사슴이 호랑이를 보고 도망치는 것처럼, 부엉이가 독수리를 보고 움츠러드는 것처럼.","JPN":"カメがサメを見て驚くように、鹿が虎を見て逃げるように、フクロウがワシを見て縮みあがるように。","ENG":"Like how a turtle gets startled seeing a shark, or a deer running away after catching a glimpse of a tiger, or even how an owl hides from an eagle.","TWN":"就像烏龜看到鯊魚會嚇到，鹿看到老虎會逃跑，貓頭鷹看到禿鷹會把身體縮起來一樣，"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"포식자 앞에서 겁에 질리는 건 생명체라면 자연스러운 방어기제니까.","JPN":"飽食者の前で怯えるのは、生命体なら自然な防衛機制なんだから。","ENG":"Trembling in fear in front of a predator is life's natural defense mechanism.","TWN":"在掠食者面前感到害怕，是很自然的反應。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"기억나, 동생? 옛날에 우리가 사냥을 하러 다닐 때?","JPN":"覚えてる？　昔私たちが狩りをしていたときのこと。","ENG":"Do you remember, Orca? When we used to go hunting?","TWN":"妹妹，你記得嗎？我們以前去狩獵時？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"매번 성공했고, 매번 새로웠잖아. 너와 내가 이런 비참한 꼴로 전락하기 전까지는.","JPN":"毎回成功して、毎回新鮮だったじゃない。あなたと私がこんな惨めな姿に転落する前までは。","ENG":"We were always successful, and it always felt new! Well, until \\"this\\" happened to us.","TWN":"在你和我淪落成這副狼狽樣之前，我們每次都成功，每次都很新鮮。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"떨어지고 나서 깨달은 거 있지? 네가 있어서 얏파한 사냥이 가능했던 거야.","JPN":"転落して気付いたんだよね。あなたがいたからヤッパ―な狩りができたってこと。","ENG":"But there's something I realized, being separated from you. I was able to do all those Yah'pa hunts! Because you were with me!","TWN":"淪落成這樣後，我發現一件事，就是因為有你，才能有開心的狩獵。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"동생은 내가 가지고 있을 때 빛이 나는 거라구. 에헷.","JPN":"あなたは私といる時に輝くのよ。えへっ。","ENG":"See, you shine the brightest when you're with me. Hehe.","TWN":"妹妹屬於我時才會發光，嘿嘿。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……싫어. 주지 않아.","JPN":"……イヤだ。あげない。","ENG":"...No. I won't let you take her.","TWN":"……不要，才不給你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"으응? 꼬마야, 내 말 안 들으려구?","JPN":"ええ？　お嬢ちゃん、私の言うことを聞かないつもり？","ENG":"Hmm? Little girl, didn't you hear what I just said?","TWN":"嗯？小鬼，你不聽我的話嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니 사실은 엄~청 무섭거든? 자꾸 말 안 들으면 혼나?","JPN":"お姉さんね、実はすっごく怖い人なんだよ？　言うこと聞かないと怒るよ？","ENG":"You know, I'm an extreeeemely dangerous person. So if you don't listen to me, you will get hurt.","TWN":"其實姊姊我很～可怕的，不聽話的話我會生氣喔！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"무섭지 않아. 오르카는 네 장신구 같은 게 아니야.","JPN":"怖くないもん。オルカはあなたのアクセサリーなんかじゃない。","ENG":"I'm not scared. Orca is not one of your trinkets.","TWN":"我不怕，奧爾卡才不是你的裝飾品。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이. 너도 어차피 버려져 있던 동생을 주운 거면서.","JPN":"ええ～、お嬢ちゃんもどうせ捨てられていた妹を拾った立場じゃない。","ENG":"C'mon. You also found her lying on the ground, didn't you?","TWN":"哎呀，反正你也是剛好撿到被拋棄的妹妹嘛。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"동생 때문에 인생이 꼬여 버렸다는 생각 안 들어? 나는 자주 들었거든.","JPN":"妹のせいで人生がダメになったって思わないの？　私は結構言われたけどな～","ENG":"Don't you think your life went downhill after that day? I heard that a lot.","TWN":"你不覺得因為妹妹的關係，害你的人生變得很複雜嗎？我常會這樣想欸！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>얘</color>도 나한테 가끔 투덜거렸어. 다 날 가지게 된 탓이라고.","JPN":"<color=#ffd34c>この子</color>もたまに私に文句言ったの。全部私を受け入れたせいなんだって。","ENG":"<color=#ffd34c>She</color> used to complain about me too. That's because she took me.","TWN":"<color=#ffd34c>她</color>也偶爾會跟我碎念，說都怪我不好。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……그래서 잡아먹은 거야?","JPN":"……だから食べちゃったの？","ENG":"Is that why you consumed her?","TWN":"……所以你就把她吃掉嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"동생도 널 잡아먹으려고 하지 않았어?","JPN":"妹はあなたを食べようとしたことない？","ENG":"Didn't my little sister try to consume you too?","TWN":"妹妹沒有想把你吃掉嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우리에게는 자연스러운 일이야. 고래가 새우를 잡아먹는 것처럼.","JPN":"私たちには自然なことだよ。クジラがエビを食べるようにね。","ENG":"It's only natural for us. Just like how a whale eats krill.","TWN":"這對我們來說是再自然不過的事，就像大鯨魚會吃小蝦米一樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"……나를 넘겨라, 숙주.","JPN":"……私を渡せ、宿主。","ENG":"...Host, give her what she wants.","TWN":"……宿主，把我交給她吧。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"왜……? 오르카도 가기 싫잖아.","JPN":"なんで……？　オルカも行きたくないんでしょう。","ENG":"Why...? I know you don't want to go.","TWN":"為什麼……？奧爾卡不是也不想離開嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"나는 네 감정에 대해 누구보다 예민하다. 어쩌면 너 자신보다 더.","JPN":"私はお前の感情に誰よりも敏感だ。もしかするとお前自身よりも。","ENG":"I'm more sensitive about your feelings than anyone. Perhaps even you.","TWN":"我比任何人都清楚你的想法，或許更勝你自己。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"여기는 네가 살아가는 장소다.","JPN":"ここはお前が暮らしている場所だ。","ENG":"But this place is where \\"you\\" live.","TWN":"這裡是你生活的地方。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"너에게 이 곳에서 함께 지낸 사람들은, 네가 아저씨라고 부르는 용병 못지 않게 소중해.","JPN":"お前にとってここで一緒に過ごしてきた人々は、お前がおじさんと呼ぶ傭兵くらい大切な存在だ。","ENG":"The people here are as valuable to you as that mercenary you call Eddie.","TWN":"和你一起在這裡生活的人，跟那個大叔一樣，對你而言都是很重要的人。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"알고 있었어…?","JPN":"知ってたの……？","ENG":"You knew all along...?","TWN":"你知道喔…？"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"나는 네 정신에 기생하고 있다. 모를 수가 없지.","JPN":"私はお前の精神に寄生している。知らないはずがない。","ENG":"How could I not? I live inside your consciousness.","TWN":"因為我寄生在你的意志裡，不得不知道。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"<color=#ffd34c>나</color>는 나를 가져가기 위해서 무슨 짓이든 저지를 거다.","JPN":"<color=#ffd34c>私</color>は私を得るために何だってするだろう。","ENG":"<color=#ffd34c>I</color> will do anything I can to get me.","TWN":"<color=#ffd34c>我</color>為了帶走我，會不計任何手段的。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"다른 인간들을 해치거나 죽일지도 모르지.","JPN":"他の人間を傷つけたり、あるいは殺すかもしれない。","ENG":"Even if it means harming or even killing other people.","TWN":"可能會傷害甚至是殺害其他人。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"불가능한 일은 아니다. 나와 가까이 있을수록 저것은 본래의 힘을 되찾고 있어.","JPN":"不可能なことではない。私の近くにいる時間が長くなるほど、あれは本来の力を取り戻す。","ENG":"It's not impossible. But the closer she is to me, the more she is regaining her former power.","TWN":"這並非不可能，和我越靠近，那傢伙就越能找回原本的力量。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"전부 알고 있으면서, 왜 오르카는 빼놓는 거야?","JPN":"全部知ってるのに、どうしてオルカは外すの？","ENG":"If you already knew, then why are you leaving yourself out?","TWN":"你明明都知道，為何還漏掉奧爾卡？"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"……나를 말인가?","JPN":"……私を？","ENG":"...You mean me?","TWN":"……你說我嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"제시카도, 찰리도. 관리부장도.","JPN":"ジェシカも、チャーリーも、管理部長も。","ENG":"Jessica, Charlie, Hana...","TWN":"潔西卡、查理、管理部長、"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"사장도, 부사장도. 조교도…….","JPN":"社長も、副社長も、ユコも……","ENG":"Boss, the Vice President, and Yoonjung...","TWN":"老闆、副總、助教……"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"모두 마시멜로를 줬어.","JPN":"みんなマシュマロをくれた。","ENG":"They all gave us marshmallows.","TWN":"他們全都給過我棉花糖。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그리고 오르카, 너랑은 항상 마시멜로를 나눠 먹었어.","JPN":"それにオルカ、あなたとはいつも一緒にマシュマロを食べた。","ENG":"And you, Orca. I always shared those marshmallows with you.","TWN":"而且奧爾卡，我總是和你一起分享棉花糖。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카 너도, 회사의 다른 사람들처럼 나에게는 소중한……","JPN":"オルカも、会社の人たちのように私には大切な……","ENG":"Just like everyone else here... You're also my...","TWN":"奧爾卡，你和公司其他人一樣，對我而言是很重要的……"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"친구야.","JPN":"友達。","ENG":"Friend.","TWN":"朋友。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"큭……. 큭큭…….","JPN":"ク……ククッ……","ENG":"Hah... Hah hah...","TWN":"咳……咳咳……"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"네 이빨은 날카롭지는 않아도 치명적으로 자랐군.","JPN":"お前の牙は鋭くはないが本質を突くようになったのだな。","ENG":"Even with dull teeth, you grew up to be quite lethal.","TWN":"你的語氣很平淡，殺傷力卻很大呢。"},"stage":{"bg":"MIND","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"이성은 본능을 통제하지. 설익은 본능은 이성을 이길 수 없다.","JPN":"理性は本能を統制する。未熟な本能は理性に勝てない。","ENG":"Normally, reason triumphs instinct. So an immature instinct can never win against reason.","TWN":"理性會控制本能，不成熟的本能是無法贏過理性的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"응. 상대는 강해. 나도 느낄 수 있어.","JPN":"うん。相手は強い。私にも感じられる。","ENG":"Okay. I know she's strong. I can feel it.","TWN":"嗯，我也有感覺到對方很強。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"그러니 이번에는 네가 내 이성이 되어 줘야 한다.","JPN":"だから今度はお前が私の理性になってもらう。","ENG":"So this time, you'll have to be my reason.","TWN":"所以這次你必須當我的理性。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"흐응. 분위기가 이상하네.","JPN":"ふーん。雰囲気がおかしいね。","ENG":"Hmm... Something's not right.","TWN":"喔呵，氣氛不太對喔。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"동생, 혹시 반항하기로 마음 먹은 거야?","JPN":"オルカ、もしかして反抗するつもり？","ENG":"Orca? Have you decided to rebel against me?","TWN":"妹妹，你是打算反抗嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"마지막까지 이빨을 감춰라. 살아 있으면 언제든 쓸 수 있어.","JPN":"最後まで牙を隠せ。生きていればいつでも使える。","ENG":"Hide your teeth until the last moment. As long as you're alive, you'll be able to use it.","TWN":"不到最後關頭都不要露出牙齒，只要活著就有機會用上。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_ORCA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"네가 절호의 기회라고 판단했을 때, 저것의 목덜미를 물어뜯는 거다.","JPN":"お前が絶好の機会と判断した時、あれのうなじを噛みちぎるのだ。","ENG":"When you think the time is right, I want you to rip her throat wide open.","TWN":"在你認爲是最好的時機，就緊咬住那傢伙的脖子。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_ORCA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……알겠어.","JPN":"……わかった。","ENG":"...Okay.","TWN":"……好。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_ORCA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"해치우자, 오르카.","JPN":"やっつけよう、オルカ。","ENG":"Let's get her, Orca.","TWN":"消滅她吧，奧爾卡。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_ORCA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};